	private static void rethrowRefusalCleanupFailure(
			LmdbNativeFactorizedRows.EnumMaterializationRefused refusal) {
		Throwable[] suppressed = refusal.getSuppressed();
		if (suppressed.length == 0) {
			return;
		}
		Throwable primary = suppressed[0];
		for (int i = 1; i < suppressed.length; i++) {
			if (suppressed[i] != primary) {
				primary.addSuppressed(suppressed[i]);
			}
		}
		if (primary instanceof RuntimeException) {
			throw (RuntimeException) primary;
		}
		if (primary instanceof Error) {
			throw (Error) primary;
		}
		throw new QueryEvaluationException(primary);
	}

	/** Emits the sorted flat rows: odometer over each row's arena runs, repeated {@code multiplicity} times. */
	private List<BindingSet> expandSortedFlatRows(NativeSortBuffer sortBuffer, int[] sortedOrder,
			int[][] enumValueSlots, LmdbNativeLongArena arena, TopKPayloadStore topKPayloads, int slotCount,
			long emitCap,
			AggContext values) {
		int enums = enumValueSlots.length;
		ArrayList<BindingSet> results = new ArrayList<>();
		long[] snapshot = new long[sortBuffer.slotCount];
		int[] odometer = new int[enums];
		for (int index : sortedOrder) {
			sortBuffer.copyRow(index, snapshot);
			long multiplicity = snapshot[slotCount];
			Arrays.fill(odometer, 0);
			while (true) {
				for (int b = 0; b < enums; b++) {
					int[] valueSlots = enumValueSlots[b];
					int at = odometer[b] * valueSlots.length;
					long valuesOffset = snapshot[slotCount + 1 + 2 * b] + at;
					for (int j = 0; j < valueSlots.length; j++) {
						snapshot[valueSlots[j]] = topKPayloads != null
								? topKPayloads.get(index, valuesOffset + j)
								: arena.get(valuesOffset + j);
					}
				}
				for (long m = 0; m < multiplicity; m++) {
					results.add(project(snapshot, values));
					if (results.size() >= emitCap) {
						return slice(results);
					}
				}
				int k = enums - 1;
				while (k >= 0) {
					odometer[k]++;
					if (odometer[k] < snapshot[slotCount + 2 + 2 * k]) {
						break;
					}
					odometer[k] = 0;
					k--;
				}
				if (k < 0) {
					break;
				}
			}
		}
		return slice(results);
	}

	List<BindingSet> projectSortedRows(NativeSortedRows sortedRows, int slotCount, long emitCap, AggContext values,
			boolean distinctAlreadyApplied) throws IOException {
		ArrayList<BindingSet> results = new ArrayList<>();
		NativeDistinctTracker distinctRows = distinct && !distinctAlreadyApplied
				? new NativeDistinctTracker(sourceSlots)
				: null;
		long[] snapshot = new long[slotCount];
		while (sortedRows.next(snapshot)) {
			if (distinctRows != null && !distinctRows.add(snapshot)) {
				continue;
			}
			results.add(project(snapshot, values));
			if (results.size() >= emitCap) {
				break;
			}
		}
		return slice(results);
	}

	Value orderValue(long id, AggContext values) {
		if (id == UNKNOWN || id == NULL_CONTEXT_ID) {
			return null;
		}
		return values.value(id);
	}

	Integer orderCompare(long leftId, long rightId, LmdbNativeValueCodec codec) {
		if (codec == null || leftId == UNKNOWN || leftId == NULL_CONTEXT_ID || rightId == UNKNOWN
				|| rightId == NULL_CONTEXT_ID) {
			return null;
		}
		if (ValueIds.isOrderedInteger(leftId) && ValueIds.isOrderedInteger(rightId)) {
			// biased value fields compare exactly like the numbers, across all ordered subtypes — no decode
			return Long.compare(ValueIds.getValue(leftId), ValueIds.getValue(rightId));
		}
		return LmdbNativeExpressionCompiler.compareDecoded(codec.decode(leftId), codec.decode(rightId));
	}

	RowCursor openPrefixRunCursor(RowState row) throws IOException {
		if (prefixRunPlan == null || prefixPattern == null || prefixPattern.hasRuntimeBoundSlot(row)) {
			return null;
		}
		long subj = prefixPattern.s.lookup(row.slots);
		long pred = prefixPattern.p.lookup(row.slots);
		long obj = prefixPattern.o.lookup(row.slots);
		long context = prefixPattern.c.lookup(row.slots);
		LmdbPrefixRunCursor cursor = source.prefixRuns(prefixRunPlan, subj, pred, obj, context, false);
		if (cursor == null) {
			return null;
		}
		return new PrefixRunRowCursor(row, prefixPattern, cursor);
	}

